Action.Str:
var raw = String(config_raw || '');
var errors = 0;
var applied = 0;

function setNumericGlobal(name, value, minValue) {
  var n = parseFloat(value);
  if (isNaN(n) || n < minValue) {
    errors++;
    return;
  }
  setGlobal(name, String(n));
  applied++;
}

function setTextGlobal(name, value) {
  var v = String(value || '').trim();
  if (!v) {
    errors++;
    return;
  }
  setGlobal(name, v);
  applied++;
}

var lines = raw.split(/\r?\n/);
for (var i = 0; i < lines.length; i++) {
  var line = String(lines[i] || '').trim();
  if (!line || line.indexOf('#') === 0) {
    continue;
  }

  var pos = line.indexOf('=');
  if (pos <= 0) {
    errors++;
    continue;
  }

  var key = line.substring(0, pos).trim();
  var value = line.substring(pos + 1).trim();

  if (key === 'LOG_DIR') {
    setTextGlobal('LOG_DIR', value);
  } else if (key === 'PLACE_RADIUS_METERS') {
    setNumericGlobal('PLACE_RADIUS_METERS', value, 0.000001);
  } else if (key === 'MIN_STOP_MINUTES') {
    setNumericGlobal('MIN_STOP_MINUTES', value, 1);
  } else if (key === 'PLACE_NAME_PREFIX') {
    setTextGlobal('PLACE_NAME_PREFIX', value);
  } else if (key === 'GPS_MAX_ACCURACY_METERS') {
    setNumericGlobal('GPS_MAX_ACCURACY_METERS', value, 0.000001);
  }
}

setGlobal('CONFIG_ERROR_COUNT', String(errors));
if (applied > 0 && errors > 0) {
  setGlobal('CONFIG_LOAD_STATUS', 'loaded_with_errors');
} else if (applied > 0) {
  setGlobal('CONFIG_LOAD_STATUS', 'loaded');
} else if (errors > 0) {
  setGlobal('CONFIG_LOAD_STATUS', 'defaults_only_with_errors');
} else {
  setGlobal('CONFIG_LOAD_STATUS', 'defaults_only');
}

// B005_RECOVERY_V1
var raw = String(rec_raw || '').replace(/^\uFEFF/, '');
var lines = raw.split(/\r?\n/).map(function(line) {
  return String(line || '').trim();
}).filter(function(line) {
  return line.length > 0;
});
var expectedHeader = 'TIMESTAMP;LAT;LON;PLACE_ID;NAME';
var pathDateMatch = /(\d{4}-\d{2}-\d{2})-significant_places\.csv$/.exec(String(log_file || ''));
var expectedDate = pathDateMatch ? pathDateMatch[1] : '';
var previousTimestamp = '';
var maxId = 0;
var lastRecord = null;
var valid = true;
var errorCode = expectedDate ? 'empty_or_header' : 'path_date';

recovery_status = 'malformed';

function validTimestamp(value) {
  var match = /^(\d{4})-(\d{2})-(\d{2}) (\d{2})\.(\d{2})$/.exec(value);
  if (!match || value.substring(0, 10) !== expectedDate) return false;
  var y = Number(match[1]);
  var m = Number(match[2]);
  var d = Number(match[3]);
  var h = Number(match[4]);
  var min = Number(match[5]);
  var parsed = new Date(y, m - 1, d, h, min, 0, 0);
  return parsed.getFullYear() === y &&
         parsed.getMonth() === m - 1 &&
         parsed.getDate() === d &&
         parsed.getHours() === h &&
         parsed.getMinutes() === min;
}

if (expectedDate && lines.length === 1 && lines[0] === expectedHeader) {
  recovery_status = 'header_only';
  errorCode = '';
} else if (expectedDate && lines.length > 1 && lines[0] === expectedHeader) {
  for (var i = 1; i < lines.length; i++) {
    var parts = lines[i].split(';');
    if (parts.length !== 5) {
      valid = false;
      errorCode = 'fields';
      break;
    }
    var timestamp = String(parts[0] || '').trim();
    var lat = Number(parts[1]);
    var lon = Number(parts[2]);
    var idText = String(parts[3] || '').trim();
    var id = Number(idText);
    var name = String(parts[4] || '').trim();
    if (!validTimestamp(timestamp)) {
      valid = false;
      errorCode = 'timestamp';
      break;
    }
    if (previousTimestamp && timestamp < previousTimestamp) {
      valid = false;
      errorCode = 'order';
      break;
    }
    if (!isFinite(lat) || lat < -90 || lat > 90) {
      valid = false;
      errorCode = 'latitude';
      break;
    }
    if (!isFinite(lon) || lon < -180 || lon > 180) {
      valid = false;
      errorCode = 'longitude';
      break;
    }
    if (!/^[1-9]\d*$/.test(idText) || !isFinite(id)) {
      valid = false;
      errorCode = 'id';
      break;
    }
    if (!name) {
      valid = false;
      errorCode = 'name';
      break;
    }
    previousTimestamp = timestamp;
    maxId = Math.max(maxId, id);
    lastRecord = {lat: lat, lon: lon, id: id, name: name};
  }
  if (valid && lastRecord) {
    rec_lat = String(lastRecord.lat);
    rec_lon = String(lastRecord.lon);
    rec_id = String(lastRecord.id);
    rec_name = lastRecord.name;
    rec_counter = String(maxId);
    recovery_status = 'recovered';
    errorCode = '';
  }
}

rec_error = errorCode || 'none';

if (recovery_status === 'malformed') {
  var errorCount = parseInt(global('RECOVERY_ERROR_COUNT'), 10);
  if (!isFinite(errorCount) || errorCount < 0) errorCount = 0;
  setGlobal('RECOVERY_ERROR_COUNT', String(errorCount + 1));
  setGlobal('RECOVERY_STATUS', 'malformed');
  setGlobal('RECOVERY_LAST_ERROR', errorCode);
} else {
  setGlobal('RECOVERY_LAST_ERROR', '');
}

var lat = parseFloat(gl_latitude);
var lon = parseFloat(gl_longitude);
var acc = parseFloat(gl_coordinates_accuracy);
var maxAcc = parseFloat(global('GPS_MAX_ACCURACY_METERS'));

var valid =
  isFinite(lat) &&
  isFinite(lon) &&
  isFinite(acc) &&
  isFinite(maxAcc) &&
  lat >= -90 &&
  lat <= 90 &&
  lon >= -180 &&
  lon <= 180 &&
  acc >= 0 &&
  maxAcc > 0 &&
  acc <= maxAcc;

setGlobal('FIX_VALID', valid ? 'true' : 'false');
setGlobal('GPS_ACCURACY', isFinite(acc) ? String(acc) : '');

function haversine(lat1, lon1, lat2, lon2) {
  var R = 6371000;
  var toRad = function(v) { return v * Math.PI / 180; };
  var dLat = toRad(lat2 - lat1);
  var dLon = toRad(lon2 - lon1);
  var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
          Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
          Math.sin(dLon / 2) * Math.sin(dLon / 2);
  var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

var raw = String(init_known_places_raw || '');
var targetLat = parseFloat(global('CURRENT_PLACE_LAT'));
var targetLon = parseFloat(global('CURRENT_PLACE_LON'));
var bestName = '';
var bestDistance = Infinity;

if (!isNaN(targetLat) && !isNaN(targetLon) && raw.trim()) {
  var lines = raw.split(/\r?\n/);
  for (var i = 0; i < lines.length; i++) {
    var line = String(lines[i] || '').trim();
    if (!line || line.indexOf('#') === 0 || line.indexOf('PLACE_KEY;') === 0) {
      continue;
    }

    var parts = line.split(';');
    if (parts.length < 5) {
      continue;
    }

    var displayName = String(parts[1] || '').trim();
    var lat = parseFloat(parts[2]);
    var lon = parseFloat(parts[3]);
    var radius = parseFloat(parts[4]);
    if (!displayName || isNaN(lat) || isNaN(lon) || isNaN(radius) || radius <= 0) {
      continue;
    }

    var distance = haversine(targetLat, targetLon, lat, lon);
    if (distance <= radius && distance < bestDistance) {
      bestDistance = distance;
      bestName = displayName;
    }
  }
}

if (bestName) {
  setGlobal('CURRENT_PLACE_NAME', bestName);
}

var lat = parseFloat(cur_lat);
var lon = parseFloat(cur_lon);
var acc = parseFloat(gl_coordinates_accuracy);
var maxAcc = parseFloat(global('GPS_MAX_ACCURACY_METERS'));

var valid =
  isFinite(lat) &&
  isFinite(lon) &&
  isFinite(acc) &&
  isFinite(maxAcc) &&
  lat >= -90 &&
  lat <= 90 &&
  lon >= -180 &&
  lon <= 180 &&
  acc >= 0 &&
  maxAcc > 0 &&
  acc <= maxAcc;

setGlobal('FIX_VALID', valid ? 'true' : 'false');
setGlobal('GPS_ACCURACY', isFinite(acc) ? String(acc) : '');

function haversine(lat1, lon1, lat2, lon2) {
  var R = 6371000;
  var toRad = function(v) { return v * Math.PI / 180; };
  var dLat = toRad(lat2 - lat1);
  var dLon = toRad(lon2 - lon1);
  var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
          Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
          Math.sin(dLon / 2) * Math.sin(dLon / 2);
  var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

var lat1 = parseFloat(cur_lat);
var lon1 = parseFloat(cur_lon);
var lat2 = parseFloat(global('CURRENT_PLACE_LAT'));
var lon2 = parseFloat(global('CURRENT_PLACE_LON'));
var radius = parseFloat(global('PLACE_RADIUS_METERS'));
var d = 999999;
var atCurrent = false;

if (!isNaN(lat1) && !isNaN(lon1) && !isNaN(lat2) && !isNaN(lon2) && !isNaN(radius)) {
  d = haversine(lat1, lon1, lat2, lon2);
  atCurrent = d <= radius;
}

setGlobal('DIST_FROM_CURRENT', String(d));
setGlobal('AT_CURRENT_PLACE', atCurrent ? 'true' : 'false');

function missing(name) {
  var v = String(global(name) || '').trim();
  return !v;
}

var needConfig = missing('LOG_DIR') ||
                 missing('PLACE_RADIUS_METERS') ||
                 missing('MIN_STOP_MINUTES') ||
                 missing('PLACE_NAME_PREFIX') ||
                 missing('GPS_MAX_ACCURACY_METERS');

var needInit = false;
var currentLogDate = String(global('CURRENT_LOG_DATE') || '').trim();

var todayFull = String(global('DATE') || '').trim();
if (!currentLogDate || !todayFull || currentLogDate !== todayFull) {
  needInit = true;
}

if (missing('CURRENT_PLACE_LAT') ||
    missing('CURRENT_PLACE_LON') ||
    missing('CURRENT_PLACE_ID') ||
    missing('CURRENT_PLACE_NAME') ||
    missing('PLACE_COUNTER')) {
  needInit = true;
}

setGlobal('NEED_CONFIG_RELOAD', needConfig ? 'true' : 'false');
setGlobal('NEED_DAILY_INIT', needInit ? 'true' : 'false');

function haversine(lat1, lon1, lat2, lon2) {
  var R = 6371000;
  var toRad = function(v) { return v * Math.PI / 180; };
  var dLat = toRad(lat2 - lat1);
  var dLon = toRad(lon2 - lon1);
  var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
          Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
          Math.sin(dLon / 2) * Math.sin(dLon / 2);
  var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

var lat1 = parseFloat(cur_lat);
var lon1 = parseFloat(cur_lon);
var lat2 = parseFloat(global('CANDIDATE_PLACE_LAT'));
var lon2 = parseFloat(global('CANDIDATE_PLACE_LON'));
var radius = parseFloat(global('PLACE_RADIUS_METERS'));
var d = 999999;
var atCandidate = false;

if (!isNaN(lat1) && !isNaN(lon1) && !isNaN(lat2) && !isNaN(lon2) && !isNaN(radius)) {
  d = haversine(lat1, lon1, lat2, lon2);
  atCandidate = d <= radius;
}

setGlobal('DIST_FROM_CANDIDATE', String(d));
setGlobal('AT_CANDIDATE_PLACE', atCandidate ? 'true' : 'false');

function haversine(lat1, lon1, lat2, lon2) {
  var R = 6371000;
  var toRad = function(v) { return v * Math.PI / 180; };
  var dLat = toRad(lat2 - lat1);
  var dLon = toRad(lon2 - lon1);
  var a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
          Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
          Math.sin(dLon / 2) * Math.sin(dLon / 2);
  var c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

var raw = String(known_places_raw || '');
var targetLat = parseFloat(next_place_lat);
var targetLon = parseFloat(next_place_lon);
var bestName = '';
var bestDistance = Infinity;

if (!isNaN(targetLat) && !isNaN(targetLon) && raw.trim()) {
  var lines = raw.split(/\r?\n/);
  for (var i = 0; i < lines.length; i++) {
    var line = String(lines[i] || '').trim();
    if (!line || line.indexOf('#') === 0 || line.indexOf('PLACE_KEY;') === 0) {
      continue;
    }

    var parts = line.split(';');
    if (parts.length < 5) {
      continue;
    }

    var displayName = String(parts[1] || '').trim();
    var lat = parseFloat(parts[2]);
    var lon = parseFloat(parts[3]);
    var radius = parseFloat(parts[4]);
    if (!displayName || isNaN(lat) || isNaN(lon) || isNaN(radius) || radius <= 0) {
      continue;
    }

    var distance = haversine(targetLat, targetLon, lat, lon);
    if (distance <= radius && distance < bestDistance) {
      bestDistance = distance;
      bestName = displayName;
    }
  }
}

if (bestName) {
  next_place_name = bestName;
}
